/**
 * Generate Close CRM firewall config.
 *
 * Data source: https://developer.close.com/
 *
 * Close is a CRM platform for sales teams.
 * Uses OAuth Bearer token authentication.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developer.close.com/";
// OAuth access token — opaque string, no fixed prefix
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalC";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Close CRM API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:close",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const closeFirewall = {",
    '  name: "close",',
    '  description: "Close CRM API",',
    "  placeholders: {",
    `    CLOSE_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.close.com/api",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.CLOSE_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Close CRM firewall config...");
  const ts = generateTypeScript();
  writeOutput("close", ts, import.meta.dirname);
}
